1	//! `web-clean` — a clean-room reimplementation of the response bodies produced
2	//! by the tamarin-prover interactive web UI.
3	//!
4	//! This crate reproduces the *web layer's* output: the URL route grammar, the
5	//! JSON response envelopes, and the HTML/DOT/text page templates. Content that
6	//! the prover produces (pretty-printed terms, constraint systems, proof-method
7	//! names, graph bodies) is treated as opaque input supplied by the caller — the
8	//! crate reproduces the scaffolding, escaping, links and envelopes around it.
9	//!
10	//! Everything here was derived from black-box observation of captured responses
11	//! and live probing; see `workspace/BEHAVIOR.md` for the observed spec.
12	//!
13	//! Module map:
14	//! * [`route`] — parse a request path into a structured route (the grammar).
15	//! * [`envelope`] — the two JSON response shapes (`{html,title}`, `{redirect}`).
16	//! * [`escape`] — HTML entity escaping.
17	//! * [`page`] — the full theory-view HTML shell (the `overview/*` pages).
18	//! * [`proofscript`] — the proof-script (west) pane and proof-tree line grammar.
19	//! * [`forms`] — the edit / delete / add-lemma form bodies.
20	//! * [`intdot`] — the `intdot` mini-page and empty-graph DOT skeleton.
21	//! * [`text`] — the plain-text bodies (`source`/`message`, `next`/`prev`).
22	//! * [`errors`] — the 404 Not Found page.
23	
24	pub mod envelope;
25	pub mod errors;
26	pub mod escape;
27	pub mod forms;
28	pub mod intdot;
29	pub mod page;
30	pub mod proofscript;
31	pub mod route;
32	pub mod text;
33	
34	mod notfound_template;
35	mod shell_template;
36

1	//! Route model for the interactive web UI.
2	//!
3	//! Every observed request path has the shape
4	//! `/thy/<theory-kind>/<index>/<handler>/<args…>` where:
5	//! * `<theory-kind>` is the analysis kind — only `trace` appears in the corpus
6	//!   (a `diff` kind is plausible but unobserved).
7	//! * `<index>` is either `#` (the "current" theory version) or a decimal number.
8	//! * `<handler>` selects the response family. Observed handlers and their
9	//!   response `kind`:
10	//!     - `main/…`                    -> JSON envelope (`{html,title}` / `{redirect}`)
11	//!     - `overview/…`                -> full-page HTML
12	//!     - `intdot/…`                  -> HTML mini-page
13	//!     - `interactive-graph-def/…`   -> DOT
14	//!     - `next/…`, `prev/…`          -> text (a navigation URL)
15	//!     - `autoprove/…`               -> JSON (`{redirect}`), or text on timeout
16	//!     - `source`, `message`         -> text (theory source)
17	//!
18	//! Under `main`, the sub-handlers are: `help`, `message`, `rules`, `tactic`,
19	//! `cases/{raw|refined}/{level}/{n}`, `lemma/{name}`, `add/{pos}`,
20	//! `edit/{name}`, `delete/{name}`, `method/{lemma}/{n}`, and
21	//! `proof/{lemma}/{path…}` (the proof path is a sequence of case-name segments,
22	//! the root being `_`).
23	//!
24	//! This module parses a path into a structured value; it is descriptive (the
25	//! route grammar as observed), not a dispatcher.
26	
27	/// Theory version selector.
28	#[derive(Debug, PartialEq, Eq, Clone)]
29	pub enum Index {
30	    /// `#` — the server's "current" theory version.
31	    Current,
32	    /// An explicit decimal version index.
33	    Num(u64),
34	}
35	
36	impl Index {
37	    fn parse(s: &str) -> Option<Index> {
38	        if s == "#" {
39	            Some(Index::Current)
40	        } else {
41	            s.parse::<u64>().ok().map(Index::Num)
42	        }
43	    }
44	}
45	
46	/// A `main/*` sub-handler.
47	#[derive(Debug, PartialEq, Eq, Clone)]
48	pub enum Main {
49	    Help,
50	    Message,
51	    Rules,
52	    Tactic,
53	    Cases { refined: bool, level: usize, n: usize },
54	    Lemma(String),
55	    Add(String),
56	    Edit(String),
57	    Delete(String),
58	    Method { lemma: String, n: usize },
59	    Proof { lemma: String, path: Vec<String> },
60	    /// Any unrecognized `main/*` tail.
61	    Other(Vec<String>),
62	}
63	
64	/// The selected handler and its arguments.
65	#[derive(Debug, PartialEq, Eq, Clone)]
66	pub enum Handler {
67	    Source,
68	    Message,
69	    Main(Main),
70	    Overview(Vec<String>),
71	    Intdot(Vec<String>),
72	    InteractiveGraphDef(Vec<String>),
73	    Next(Vec<String>),
74	    Prev(Vec<String>),
75	    Autoprove(Vec<String>),
76	    /// Unrecognized handler with its raw tail.
77	    Other { name: String, tail: Vec<String> },
78	}
79	
80	/// A parsed route.
81	#[derive(Debug, PartialEq, Eq, Clone)]
82	pub struct Route {
83	    pub theory_kind: String,
84	    pub index: Index,
85	    pub handler: Handler,
86	}
87	
88	fn owned(v: &[&str]) -> Vec<String> {
89	    v.iter().map(|s| s.to_string()).collect()
90	}
91	
92	fn parse_main(tail: &[&str]) -> Main {
93	    match tail {
94	        ["help"] => Main::Help,
95	        ["message"] => Main::Message,
96	        ["rules"] => Main::Rules,
97	        ["tactic"] => Main::Tactic,
98	        ["cases", kind, level, n]
99	            if (*kind == "raw" || *kind == "refined")
100	                && level.parse::<usize>().is_ok()
101	                && n.parse::<usize>().is_ok() =>
102	        {
103	            Main::Cases {
104	                refined: *kind == "refined",
105	                level: level.parse().unwrap(),
106	                n: n.parse().unwrap(),
107	            }
108	        }
109	        ["lemma", name] => Main::Lemma((*name).to_string()),
110	        ["add", pos] => Main::Add((*pos).to_string()),
111	        ["edit", name] => Main::Edit((*name).to_string()),
112	        ["delete", name] => Main::Delete((*name).to_string()),
113	        ["method", lemma, n] if n.parse::<usize>().is_ok() => Main::Method {
114	            lemma: (*lemma).to_string(),
115	            n: n.parse().unwrap(),
116	        },
117	        [proof, lemma, rest @ ..] if *proof == "proof" => Main::Proof {
118	            lemma: (*lemma).to_string(),
119	            path: owned(rest),
120	        },
121	        _ => Main::Other(owned(tail)),
122	    }
123	}
124	
125	impl Route {
126	    /// Parse a request path such as `/thy/trace/#/main/proof/exec/_/B_2`.
127	    /// Returns `None` if the path is not under `/thy/<kind>/<index>/…`.
128	    pub fn parse(path: &str) -> Option<Route> {
129	        let trimmed = path.strip_prefix('/').unwrap_or(path);
130	        let segs: Vec<&str> = trimmed.split('/').collect();
131	        // Need at least: thy / kind / index / handler
132	        if segs.len() < 4 || segs[0] != "thy" {
133	            return None;
134	        }
135	        let theory_kind = segs[1].to_string();
136	        let index = Index::parse(segs[2])?;
137	        let handler_name = segs[3];
138	        let tail = &segs[4..];
139	        let handler = match handler_name {
140	            "source" => Handler::Source,
141	            "message" => Handler::Message,
142	            "main" => Handler::Main(parse_main(tail)),
143	            "overview" => Handler::Overview(owned(tail)),
144	            "intdot" => Handler::Intdot(owned(tail)),
145	            "interactive-graph-def" => Handler::InteractiveGraphDef(owned(tail)),
146	            "next" => Handler::Next(owned(tail)),
147	            "prev" => Handler::Prev(owned(tail)),
148	            "autoprove" => Handler::Autoprove(owned(tail)),
149	            other => Handler::Other {
150	                name: other.to_string(),
151	                tail: owned(tail),
152	            },
153	        };
154	        Some(Route {
155	            theory_kind,
156	            index,
157	            handler,
158	        })
159	    }
160	}
161	
162	#[cfg(test)]
163	mod tests {
164	    use super::*;
165	
166	    #[test]
167	    fn parses_main_rules() {
168	        let r = Route::parse("/thy/trace/#/main/rules").unwrap();
169	        assert_eq!(r.theory_kind, "trace");
170	        assert_eq!(r.index, Index::Current);
171	        assert_eq!(r.handler, Handler::Main(Main::Rules));
172	    }
173	
174	    #[test]
175	    fn parses_cases_with_numbers() {
176	        let r = Route::parse("/thy/trace/1/main/cases/refined/0/2").unwrap();
177	        assert_eq!(r.index, Index::Num(1));
178	        assert_eq!(
179	            r.handler,
180	            Handler::Main(Main::Cases { refined: true, level: 0, n: 2 })
181	        );
182	    }
183	
184	    #[test]
185	    fn parses_proof_path() {
186	        let r = Route::parse("/thy/trace/3/main/proof/exec/_/B_2").unwrap();
187	        assert_eq!(
188	            r.handler,
189	            Handler::Main(Main::Proof {
190	                lemma: "exec".to_string(),
191	                path: vec!["_".to_string(), "B_2".to_string()],
192	            })
193	        );
194	    }
195	
196	    #[test]
197	    fn parses_method_and_dot_and_text() {
198	        assert_eq!(
199	            Route::parse("/thy/trace/#/main/method/exec/1").unwrap().handler,
200	            Handler::Main(Main::Method { lemma: "exec".to_string(), n: 1 })
201	        );
202	        assert!(matches!(
203	            Route::parse("/thy/trace/#/interactive-graph-def/proof/exec").unwrap().handler,
204	            Handler::InteractiveGraphDef(_)
205	        ));
206	        assert_eq!(
207	            Route::parse("/thy/trace/#/source").unwrap().handler,
208	            Handler::Source
209	        );
210	    }
211	
212	    #[test]
213	    fn rejects_non_thy() {
214	        assert!(Route::parse("/static/css/x.css").is_none());
215	        assert!(Route::parse("/").is_none());
216	    }
217	}
