1	//! The proof-script (west) pane markup embedded in the theory-view page and in
2	//! the `main/*` navigation.
3	//!
4	//! ## Line model (observed)
5	//! The pane is a flat sequence of logical lines. Rendering emits each line's
6	//! text followed by the literal `"<br/>\n"`, and finally a single trailing
7	//! space `" "`. A blank line is an element whose text is empty (yielding a lone
8	//! `"<br/>\n"`). This one rule reproduces the exact blank-line spacing of both
9	//! the no-lemma and multi-lemma captures.
10	//!
11	//! ## Element order
12	//! 1. `theory NAME begin` header line
13	//! 2. one blank + link line per theory item, in order: Message theory, rules,
14	//!    Tactic(s), Raw sources, Refined sources
15	//! 3. one blank + the `add lemma` link for position `<first>`
16	//! 4. for each lemma: one blank, the lemma's body lines, one blank, the lemma's
17	//!    trailing `add lemma` link (targeting that lemma's name)
18	//! 5. one blank + `end`
19	//!
20	//! When there are zero lemmas, step 4 contributes nothing, which leaves TWO
21	//! blank lines between the `<first>` add-link and `end` (matching the capture).
22	//!
23	//! ## Slots that come from the prover (opaque here)
24	//! The lemma declaration HTML (`decl_html`: the pretty-printed `lemma NAME:` +
25	//! quantifier + formula, already entity-escaped and wrapped in `hl_operator`
26	//! spans), the rules label/count, the sources descriptions, and — for a solved
27	//! proof — each proof step's method HTML and case names. Everything else (the
28	//! anchors, keywords, indentation, links) is generated here.
29	//!
30	//! ## Indices
31	//! Every internal href uses the resolved numeric theory index, never `#`.
32	
33	/// A theory item shown as a top link in the proof-script pane.
34	pub enum Item<'a> {
35	    /// `Message theory` link.
36	    Message,
37	    /// Multiset rewriting rules link. `label` is the prover's wording
38	    /// (`"Multiset rewriting rules"`, or with `" and restrictions"`), `count`
39	    /// the rule count.
40	    Rules { label: &'a str, count: usize },
41	    /// `Tactic(s)` link.
42	    Tactic,
43	    /// `Raw sources` link; `desc` e.g. `"4 cases, deconstructions complete"`.
44	    RawSources { desc: &'a str },
45	    /// `Refined sources` link; note the label carries a trailing space.
46	    RefinedSources { desc: &'a str },
47	}
48	
49	/// How a lemma's proof is displayed.
50	pub enum Proof<'a> {
51	    /// Unproven: a single `by sorry` proof-step line. The declaration and the
52	    /// edit/delete line are emitted bare (no status wrapper).
53	    Sorry,
54	    /// A solved/partial proof rendered as an explicit list of proof lines.
55	    ///
56	    /// Observed: when a lemma carries a proof, the whole lemma header — the
57	    /// declaration HTML plus the following edit/delete line — is wrapped in a
58	    /// single `<span class="{status}">…</span>` reflecting the lemma's overall
59	    /// proof status (`hl_good` for the proved lemmas in the corpus). The wrapper
60	    /// opens immediately before the declaration and closes right after the
61	    /// delete-lemma anchor (spanning the intervening `<br/>` line breaks).
62	    Steps {
63	        /// Lemma-level status class carried by the header wrapper span.
64	        status: &'a str,
65	        /// The rendered proof-tree lines, in document order.
66	        lines: Vec<ProofLine<'a>>,
67	    },
68	}
69	
70	/// One line of a rendered proof tree.
71	pub enum ProofLine<'a> {
72	    /// A proof-method step (an applied method or a leaf such as `SOLVED`).
73	    Step {
74	        depth: usize,
75	        /// Status class, e.g. `"hl_good"`.
76	        status: &'a str,
77	        /// Full href, e.g. `/thy/trace/3/main/proof/exec/_/B_2`.
78	        href: String,
79	        /// Prover method HTML, e.g. `<span class="hl_keyword">simplify</span>`.
80	        method_html: &'a str,
81	        /// Annotation shown in the remove-step anchor (usually empty).
82	        annotation: &'a str,
83	        /// Whether the line is prefixed with a wrapped `by ` keyword.
84	        by: bool,
85	    },
86	    /// A `case NAME` header.
87	    Case {
88	        depth: usize,
89	        status: &'a str,
90	        name: &'a str,
91	    },
92	    /// A `next` separator between sibling cases.
93	    Next { depth: usize, status: &'a str },
94	    /// A `qed` closing a case block.
95	    Qed { depth: usize, status: &'a str },
96	}
97	
98	/// A single lemma block.
99	pub struct Lemma<'a> {
100	    /// Lemma name (used in the edit/delete/add/proof links).
101	    pub name: &'a str,
102	    /// Opaque prover-produced declaration HTML (`lemma NAME:` + formula).
103	    pub decl_html: &'a str,
104	    /// Proof display.
105	    pub proof: Proof<'a>,
106	}
107	
108	/// The whole proof-script pane input.
109	pub struct Overview<'a> {
110	    pub theory_name: &'a str,
111	    pub index: u64,
112	    pub items: Vec<Item<'a>>,
113	    pub lemmas: Vec<Lemma<'a>>,
114	}
115	
116	fn indent(depth: usize) -> String {
117	    "&nbsp;&nbsp;".repeat(depth)
118	}
119	
120	/// Render one proof-tree line (public so the line grammar can be unit-tested).
121	pub fn render_proof_line(line: &ProofLine) -> String {
122	    match line {
123	        ProofLine::Step {
124	            depth,
125	            status,
126	            href,
127	            method_html,
128	            annotation,
129	            by,
130	        } => {
131	            let ind = indent(*depth);
132	            let by_prefix = if *by {
133	                format!(r#"<span class="{status}"><span class="hl_keyword">by</span> </span>"#)
134	            } else {
135	                String::new()
136	            };
137	            format!(
138	                r#"{ind}{by_prefix}<a class="internal-link proof-step {status}" href="{href}">{method_html}</a><a class="internal-link remove-step" href="{href}">{annotation}</a>"#
139	            )
140	        }
141	        ProofLine::Case {
142	            depth,
143	            status,
144	            name,
145	        } => format!(
146	            r#"{}<span class="{status}"><span class="hl_keyword">case</span> {name}</span>"#,
147	            indent(*depth)
148	        ),
149	        ProofLine::Next { depth, status } => format!(
150	            r#"{}<span class="{status}"><span class="hl_keyword">next</span></span>"#,
151	            indent(*depth)
152	        ),
153	        ProofLine::Qed { depth, status } => format!(
154	            r#"{}<span class="{status}"><span class="hl_keyword">qed</span></span>"#,
155	            indent(*depth)
156	        ),
157	    }
158	}
159	
160	fn item_line(item: &Item, idx: u64) -> String {
161	    match item {
162	        Item::Message => format!(
163	            r#"<a class="internal-link" href="/thy/trace/{idx}/main/message"><strong>Message theory</strong> </a>"#
164	        ),
165	        Item::Rules { label, count } => format!(
166	            r#"<a class="internal-link" href="/thy/trace/{idx}/main/rules"><strong>{label}</strong> ({count})</a>"#
167	        ),
168	        Item::Tactic => format!(
169	            r#"<a class="internal-link" href="/thy/trace/{idx}/main/tactic"><strong>Tactic(s)</strong> </a>"#
170	        ),
171	        Item::RawSources { desc } => format!(
172	            r#"<a class="internal-link" href="/thy/trace/{idx}/main/cases/raw/0/0"><strong>Raw sources</strong> ({desc})</a>"#
173	        ),
174	        Item::RefinedSources { desc } => format!(
175	            r#"<a class="internal-link" href="/thy/trace/{idx}/main/cases/refined/0/0"><strong>Refined sources </strong> ({desc})</a>"#
176	        ),
177	    }
178	}
179	
180	fn add_link(idx: u64, target: &str) -> String {
181	    format!(r#"<a class="internal-link add" href="/thy/trace/{idx}/main/add/{target}">add lemma</a>"#)
182	}
183	
184	fn edit_delete_line(idx: u64, name: &str) -> String {
185	    format!(
186	        r#"<a class="internal-link edit" href="/thy/trace/{idx}/main/edit/{name}">edit lemma</a>  or  <a class="internal-link delete" href="/thy/trace/{idx}/main/delete/{name}">delete lemma</a>"#
187	    )
188	}
189	
190	fn sorry_line(idx: u64, name: &str) -> String {
191	    format!(
192	        r#"<span class="hl_keyword">by</span> <a class="internal-link proof-step sorry-step" href="/thy/trace/{idx}/main/proof/{name}"><span class="hl_keyword">sorry</span></a>"#
193	    )
194	}
195	
196	/// The theory header line: `theory NAME begin`.
197	fn header_line(name: &str, idx: u64) -> String {
198	    format!(
199	        r#"<span class="hl_keyword">theory</span> <a class="internal-link help" href="/thy/trace/{idx}/main/help">{name}</a> <span class="hl_keyword">begin</span>"#
200	    )
201	}
202	
203	/// Render the full inner HTML of the `#proof` west pane.
204	pub fn render_proof_script(o: &Overview) -> String {
205	    let idx = o.index;
206	    // Build the flat element list.
207	    let mut elems: Vec<String> = Vec::new();
208	    elems.push(header_line(o.theory_name, idx));
209	    for item in &o.items {
210	        elems.push(String::new());
211	        elems.push(item_line(item, idx));
212	    }
213	    elems.push(String::new());
